      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const membersService = require('../service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid request body');
  }

  const project = membersService.getProject(req.params.projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  const member = membersService.addMember(req.params.projectId, { userId, role });
  if (!member) {
    return sendError(res, 409, 'CONFLICT', 'Member already exists in the project');
  }

  res.status(201).json({ member });
});

module.exports = router;
