      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const projectsService = require('./service');

const router = express.Router();

router.get('/:projectId', (req, res) => {
  const project = projectsService.getProject(req.params.projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.json({ project });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid request body');
  }
  const newProject = projectsService.addProject({ name });
  res.status(201).json({ project: newProject });
});

module.exports = router;
